4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having fewer than 2 neighbors", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2 square) unchanged as a still life", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should keep a live cell with exactly 2 neighbors alive", () => {
20	    // Three cells in a row: (0,0), (1,0), (2,0). The center cell (1,0) has exactly 2 neighbors.
21	    const cells: [number, number][] = [[0, 0], [1, 0], [2, 0]];
22	    const result = nextGeneration(cells);
23	    expect(result).toContainEqual([1, 0]);
24	  });
25	  it("should keep a live cell with exactly 3 neighbors alive", () => {
26	    // L-shape: (0,0), (1,0), (0,1), (1,1). The cell (0,0) has exactly 3 neighbors.
