1	function toKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function parseKey(key: string): [number, number] {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	}
9	
10	function neighborKeys(x: number, y: number): string[] {
11	  const keys: string[] = [];
12	  for (let dx = -1; dx <= 1; dx++) {
13	    for (let dy = -1; dy <= 1; dy++) {
14	      if (dx === 0 && dy === 0) continue;
15	      keys.push(toKey(x + dx, y + dy));
16	    }
17	  }
18	  return keys;
19	}
20	
21	function countNeighbors(x: number, y: number, alive: Set<string>): number {
22	  return neighborKeys(x, y).filter((key) => alive.has(key)).length;
23	}
24	
25	export function nextGeneration(cells: [number, number][]): [number, number][] {
26	  const alive = new Set(cells.map(([x, y]) => toKey(x, y)));
27	
28	  const survivors = cells.filter(([x, y]) => {
29	    const neighbors = countNeighbors(x, y, alive);
30	    return neighbors === 2 || neighbors === 3;
31	  });
32	
33	  const deadCandidates = new Set<string>();
34	  for (const [x, y] of cells) {
35	    for (const key of neighborKeys(x, y)) {
36	      if (!alive.has(key)) deadCandidates.add(key);
37	    }
38	  }
39	
40	  const born: [number, number][] = [];
41	  for (const key of deadCandidates) {
42	    const [x, y] = parseKey(key);
43	    if (countNeighbors(x, y, alive) === 3) {
44	      born.push([x, y]);
45	    }
46	  }
47	
48	  return [...survivors, ...born];
49	}
